function reportesDeMisDependientes($empl){
    require("config.php");
     
    $sql = "SELECT * FROM reportesconsultas";

    $soli = "";
    $id = "";
    if ($rc= $conexion -> query($sql)); while($f = $rc -> fetch_array()){  
        $soli = $soli.$f['solicitante'].'/';   
        $id = $id.$f['idConsulta'].'/';
    }
    $solicitantes = explode('/', $soli);
    $ids = explode('/', $id);
    
    $sihayrep="";
    for ($i=0; $i < sizeof($solicitantes) ; $i++) { 
        for($j=0; $j<sizeof($empl); $j++){
            if(($empl[$j] == $solicitantes[$i]) and (($empl[$j]!=null) and ($solicitantes[$i]!=null)) ){
                //echo $sihayrep.'-';
               $sihayrep = $sihayrep.$ids[$i].'/';
            }
        }
    }
    $repVer = explode('/', $sihayrep);
    
    return $repVer;
}

