    inner join cp_nuevosdocumentos as nd on nd.turnadoa = em.dpto 
    where nd.id = ".$numcaso.")
    GROUP BY em.nitavu
    ";
}*/
    
 //echo $sql;
    $empl = '';
    $r = $conexion -> query($sql);
    while($f = $r -> fetch_array())
    { // resultado de la busqueda.................
        $empl = $empl.'/'.$f['nitavu'];
    }
    $empl= trim($empl, '/');
    $empleados = explode('/',$empl);
    
    return $empleados;
}


