function guardarBDFile($tramite,$campo,$dato,$tmp,$tipo,$operacion,$nitavu){
    require("config.php");
    //Si es 1 es INSERT
    if($operacion=='insert'){
       // echo '<script>alert("entro insert archivo")</script>';
        $numDocumento = ndoctramite(TRUE);
        $nombreArchivo = $numDocumento.'_'.$dato;
       // $archivo = "tramites/".$numDocumento.'_'.$dato."";
        //$subida = FTP_subir($tmp,$archivo);
       
        //sube archivo a Carpeta 
            $ruta_destino_archivo = "tmp/tramites/".$numDocumento.'_'.$dato;
            $archivo_ok = move_uploaded_file($tmp, $ruta_destino_archivo);
            
        if ($archivo_ok){
                
        //if ($subida == "TRUE"){
           
            $sql = "INSERT INTO TramitesInformacion(IdTramite, IdRequisito, Dato, TipoRequisito,NitavuCaptura,Fecha,Hora) 
            VALUES ('$tramite', '$campo', '$nombreArchivo','$tipo','$nitavu','$fecha','$hora')";
            if ($conexion->query($sql) == TRUE){ 
                ndoctramite(FALSE);  
                return TRUE;
            }else{
                return FALSE;
            }
        }else{
            return FALSE;
        }
        
    }else{
        //echo '<script>alert("entro update archivo")</script>';
        //echo $tipo;
        //echo $campo;
        if(!empty($dato)){

            //echo 'si trae archivo';
            $res = cancelarUltimoDocumentoSubido($tramite,$campo);
            //echo 'res'.$res;
            if($res==TRUE){
                //echo 'cancelo';
                $numDocumento = ndoctramite(TRUE);
                $nombreArchivo = $numDocumento.'_'.$dato;
                $ruta_destino_archivo = "tmp/tramites/".$numDocumento.'_'.$dato;
                $archivo_ok = move_uploaded_file($tmp, $ruta_destino_archivo);
                    
                if ($archivo_ok){           
                    $sql = "INSERT INTO TramitesInformacion(IdTramite, IdRequisito, Dato, TipoRequisito,NitavuCaptura,Fecha,Hora) 
                    VALUES ('$tramite', '$campo', '$nombreArchivo','$tipo','$nitavu','$fecha','$hora')";
                    if ($conexion->query($sql) == TRUE){ 
                        ndoctramite(FALSE);  
                        return TRUE;
                    }else{
                        return FALSE;
                    }
                }else{
                    return FALSE;
                }
            }
           
        }
    }
}
     
