function cualVistoBuenoSoy($dpto,$id){
    require("config.php");

    $sql = "select VoBo1, VoBo2, VoBo3, VoBo4, VoBo5 from TramitesTipo WHERE IdTipoTramite=".$id."";
    //echo $sql;
  
	$rc= $conexion -> query($sql);
	if($f = $rc -> fetch_array()){	
        if($f['VoBo1']==$dpto){
            return "VoBo1";
        }else if($f['VoBo2']==$dpto){
            return "VoBo2";
        }else if($f['VoBo3']==$dpto){
            return "VoBo3";
        }else if($f['VoBo4']==$dpto){
            return "VoBo4";
        }else if($f['VoBo5']==$dpto){
            return "VoBo5";
        }
    }else{
        return "FALSE";
    }
}

