    endswitch;
        $factor = $factor - 1;
    }

    $Digito_verificador = trim(10 - fmod($ACUMULA,10));
    //echo 'digito '.$Digito_verificador;
    $cadenacurp = $Rfc17.$Digito_verificador;

    //curp = cadenacurp
    $curp = $pos1a4.$pos5y6.$pos7y8.$pos9y10.$pos11.$pos12y13.$pos14a16;
