function TramiteDatoExtendida($FolioTramite, $IdRequisito, $IdCategoria){
    require("config.php");	
    $sql = "select TipoRequisito from TramitesRequisitos WHERE IdRequisito='".$IdRequisito."'";
    $rc= $conexion -> query($sql);
	if($f = $rc -> fetch_array())
	{				
		if($f['TipoRequisito']=='select'){
            $sql = "select Dato from TramitesInformacion WHERE IdTramite='".$FolioTramite."'  AND IdRequisito='".$IdRequisito."' and Clase = ".$IdCategoria."";
            //echo $sql;
            $rc1= $conexion -> query($sql);
            if($f1 = $rc1 -> fetch_array())
            {			
                if(strpos($f1['Dato'], '_')===false){
                   
                    $sql2 = "select * from TramitesOpcionesRequisitos WHERE IdRequisito='".$IdRequisito."'";
            
                    $rc2 = $conexion -> query($sql2);
                    while($f2 = $rc2 -> fetch_array())
                    { 
                        if($f2['IdOpcion']==$f1['Dato']){
                            $res = $f2['Opcion'];
                        }
                    }
                    return $res;
                }else{
                   
                    $ids = explode("_", $f1['Dato']);
                   
                    $sql2 = "select * from TramitesOpcionesRequisitos WHERE IdRequisito='".$IdRequisito."' and ReqDepende=".$ids[1]." and IdOpcionDepende=".$ids[2]."";
                   
                    $res="";
                    $rc2 = $conexion -> query($sql2);
                    while($f2 = $rc2 -> fetch_array())
                    { 
                        
                        if($f2['IdOpcion']==$ids[0]){
                           $res = $f2['Opcion'];
                        }
                    }
                    return $res;
                }	  
            }else{
                return FALSE;
            }

            

        }else{
            $sql = "select Dato from TramitesInformacion WHERE IdTramite='".$FolioTramite."'  AND IdRequisito='".$IdRequisito."' and Clase = ".$IdCategoria."";
            //echo $sql;
            $rc1= $conexion -> query($sql);
            if($f1 = $rc1 -> fetch_array())
            {				
                return $f1['Dato'];
            }else{
                return FALSE;
            }
        }	
	}else{
        return FALSE;
    }

  

}

