function construirFormulario($idTipoSolicitud,$FolioTramite,$nitavu,$tipoInfo){
    require("config.php");
  
    $ti = "";
    $sql = "select distinct sol.IdCatRequisitos, cat.Nombre
    from SolicitudesListaReq as sol 
    inner join SolicitudesRequisitos as req on sol.IdRequisito = req.IdRequisito
    inner join SolicitudesRequisitosCat as cat on sol.IdCatRequisitos = cat.IdCatRequisitos where IdTipoSolicitud=".$idTipoSolicitud." order by sol.IdCatRequisitos, sol.IdRequisito";
    //echo $sql;
    $rCat= $conexion -> query($sql); 
