    $sql = 'SELECT Trabaja FROM datosempleosol WHERE IdDelegacion ="'.$IdDelegacion.'" and IdPrograma="'.$IdPrograma.'" and Folio="'.$Folio.'"';
    //echo $sql;
    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array()){				
        
        if($f['Trabaja']==1){
            	
            return 'SI';
        }else if($f['Trabaja']==0){
            return 'NO';
            
        }else{
            return 'NO CAPTURADO';
        }
        
    }else{
        return FALSE;
    }
}

function ocupacionBeneficiarioVivienda($IdDelegacion,$IdPrograma,$Folio){
    require("config.php");
    $sql = 'SELECT IdOcupacion FROM datosempleosol WHERE IdDelegacion ="'.$IdDelegacion.'" and IdPrograma="'.$IdPrograma.'" and Folio="'.$Folio.'"';
    //echo $sql;
    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array()){				
        
        $ocupacion = $f['IdOcupacion'];
            	
        if($ocupacion <>''){
            $sql1 = 'SELECT Ocupacion FROM OCUPACIONES where IdOcupacion = '.$ocupacion.'';
            $rc1= $Vivienda -> query($sql1);
            if($f1 = $rc1 -> fetch_array()){	
                return $f1['Ocupacion'];
            }else{
                return FALSE;
            }
        }else{
            return 'NO CAPTURADO';
        }
        
    }else{
        return FALSE;
    }
}

