function municipioDondeQuiereLoteVivienda($IdDelegacion,$IdPrograma,$Folio){
    require("config.php");
    $sql = 'SELECT IdMunSolLote FROM solicitudes WHERE IdDelegacion ="'.$IdDelegacion.'" and IdPrograma="'.$IdPrograma.'" and Folio="'.$Folio.'"';
    //echo $sql;
    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array()){	
        if($f['IdMunSolLote']<>''){
            $sql1= 'SELECT Municipio FROM MUNICIPIOS WHERE  IdMunicipio = '.$f['IdMunSolLote'].'';
            $rc1= $Vivienda -> query($sql1);
            if($f1 = $rc1 -> fetch_array()){	
                return $f1['Municipio'];
            }else{
                return FALSE;
            }
        }else{
            return 'NO CAPTURADO';
        }			
            
    }else{
        return FALSE;
    }
}
