function eliminarTemporalesalCancelarModificacion($FolioTramite, $tipoInfo){
    require("config.php");
    $sql = 'DELETE FROM SoilicitudesTemp WHERE IdSolicitud='.$FolioTramite.'';
    if ($conexion->query($sql) == TRUE){
        $sql = 'DELETE FROM SoilicitudesInformacion WHERE IdSolicitud='.$FolioTramite.'';
        if ($conexion->query($sql) == TRUE){
            echo "<script>NPush('Se cancelo la modificación con éxito','Plataforma ITAVU')</script>";
        }else{
            echo "<script>NPush('ERROR al cancelar la modificación con éxito','Plataforma ITAVU')</script>";
        }
    }else{
        echo "<script>NPush('ERROR al cancelar la modificación con éxito','Plataforma ITAVU')</script>";
    }
}

