function obtenerOrigenDeEnvio($IdPrograma, $IdDelegacion, $Folio){
    require("config.php");
    $sql = 'SELECT OrigenDeEnvio FROM solicitudes WHERE IdDelegacion = '.$IdDelegacion.' and IdPrograma = '.$IdPrograma.' and Folio='.$Folio.'';

    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array()){				
        return $f['OrigenDeEnvio'];
        
    }else{
        return FALSE;
    }
}

function buscarTipoEvaluacion($idPrograma){
    require("config.php");
    $sql = 'select IdTipoEvaluacion from PROGRAMA where IdPrograma = '.$idPrograma.'';

    $rc= $Vivienda -> query($sql);
    if($f = $rc -> fetch_array()){				
        return $f['IdTipoEvaluacion'];
        
    }else{
        return FALSE;
    }
}

function construirEvaluacion($idTipoEvaluacion,$FolioTramite,$nitavu, $IdPrograma, $tipoInfo){
    require("config.php");
  
    $ti = "";
    $sql = "select distinct sol.IdCatRequisitos, cat.Nombre
    from SolicitudesListaReqEvaluacion as sol 
    inner join SolicitudesRequisitos as req on sol.IdRequisito = req.IdRequisito
    inner join SolicitudesRequisitosCat as cat on sol.IdCatRequisitos = cat.IdCatRequisitos where IdTipoSolicitud=".$idTipoEvaluacion." order by sol.IdCatRequisitos, sol.IdRequisito";
    //echo $sql;
    $rCat= $conexion -> query($sql); 
    while($fCat = $rCat -> fetch_array()) {    
        $IdCategoria = $fCat['IdCatRequisitos'];
        $ti = $ti. "<h3 style='
        color: white;
        background-color: #ccc;
        padding: 5px;
        margin: 0px;
        '><table width=100%><tr><td width=30px><img src='icon/page.png' style='width:20px;'></td><td>".$fCat['Nombre']."</td>";
       
