        $ti = $ti. "<div id='Categoria".$fCat['IdCatRequisitos']."'style='background-color:#EBE8DE; text-aling:left; width:100%;'>"; 
        $ti = $ti. "<div class='accordion' style='width:100%; margin: 0px;font-size: 10pt;font-family:Light; text-transform: uppercase;'>".$fCat['Nombre']."<img src='icon/flecha_abajo.png' style='width:18px; opacity:0.5'></div>";
 
        $ti = $ti. "<div class='panel'>";
          $sql2 ="select sol.IdRequisito, req.NombreRequisito, req.Descripcion, req.TipoRequisito, req.Catalogo, sol.IdCatRequisitos, cat.Nombre, sol.Opcional from SolicitudesListaReqEvaluacion as sol inner join SolicitudesRequisitos as req on sol.IdRequisito = req.IdRequisito inner join SolicitudesRequisitosCat as cat on sol.IdCatRequisitos = cat.IdCatRequisitos 
          where sol.IdTipoSolicitud=".$idTipoEvaluacion." and sol.IdCatRequisitos = ".$IdCategoria." order by IdCatRequisitos, IdRequisito";
        //echo $sql2;
          $rxx= $conexion -> query($sql2); 
          while($f2 = $rxx -> fetch_array()) {

            $IdRequisito= $f2['IdRequisito'];
            $type = $f2['TipoRequisito'];
            $NombreDelRequisito = $f2['NombreRequisito'];
