function NumeroDePago($IdDelegacion, $IdPrograma, $Folio){
    require("config.php");
    $sql = 'SELECT Max(NumPago) as NumPago FROM pagos WHERE  IdDelegacion = '.$IdDelegacion.' and IdPrograma = '.$IdPrograma.' and Folio = '.$Folio.' and NumPago <> 99';
