function agregarPagosdeAhorro($Folio, $IdPrograma, $IdDelegacion, $NumContrato, $nitavu){
    require("config.php");
    $sql4 = 'SELECT * FROM pagos WHERE Folio = '.$Folio.' and IdPrograma ='.$IdPrograma.' and IdDelegacion='.$IdDelegacion.' order by NumPago ASC';
    echo $sql4;
    $r = $conexion -> query($sql4); 
    $r_count = $r -> num_rows;
    $vuelta = 1;
    $res = '';
    if($r_count > 0){
        while($f = $r -> fetch_array()){

            /*(VVP_NumContrato, VVP_NumMov,VVP_MontoPagoRecibido, VVP_FechaOperacion, VVP_FechaCorte, VVP_FechaInicia, VVP_FechaTermina, VVP_RezGts, VVP_RezGtsCubierto, VVP_GtsPeriodo, 
            VVP_GtsPeriodoCubiertos, VVP_NuevoRezGts,  VVP_RezSeg, VVP_RezSegCubierto, VVP_SegPeriodo, VVP_SegPeriodoCubierto, VVP_NuevoRezSeg, VVP_RezOtrosGts, VVP_RezOtrosGtsCubierto, VVP_OtrosGtsPeriodo, 
            VVP_OtrosGtsPeriodoCubierto, VVP_NuevoRezOtrosGts, VVP_RezMoratorios, VVP_RezMoratoriosCubierto, VVP_MoratoriosPeriodo, VVP_NuevoRezMoratorios, VVP_RezFinanc, VVP_RezFinancCubierto, VVP_FinancPeriodo, 
            VVP_FinancPeriodoCubierto, VVP_NuevoRezFinanc, VVP_RezCapital, VVP_RezCapitalCubierto, VVP_CapitalPeriodo, VVP_CapitalPeriodoCubierto, VVP_NuevoRezCapital, VVP_AplicadoExcedente, VVP_SaldoCapitalCorriente, 
            VVP_Origen, VVP_TipoMov, VVP_Observaciones, VVP_Enviar, VVP_IdEmpCrea, VVP_IdEmpModifica, VVP_FechaCaptura, VVP_FechaUltimaMod, VVP_FechaEnvio, VVP_saldoexento, VVP_ImpSF002, VVP_FechaImpSF002,
            VVP_FechaReimSF002, VVP_ReferenciaOpd, VVP_RefBancariaOpd, VVP_IdMovDesc, VVP_Observacion2, VVP_IdFormaPago, VVP_IdSupervisor, VVP_OrigenDeEnvio, VVP_Cancelado, VVP_NumMovErroneo, VVP_OriginData)*/
            $saldoCapitalCorriente = saldoCapitalCorriente($NumContrato);
            echo '<br>'.$saldoCapitalCorriente.'<br>';
           
            $nuevoSaldoCapitalCorriente = $saldoCapitalCorriente - $f['Importe'];
            $NumMov = NumMov($NumContrato) + 1;
            $fechaCorte = ObtenerFechaCorteContrato();

            $fechaOperacion = cambiarDiagonalesdeFecha($f['FechaCaptura']);          
            
    
            if($vuelta == $r_count){
                $sql5 = "CALL registrarHistoricoPagos('$NumContrato','$NumMov','".$f['Importe']."','".$fechaOperacion."','".$fechaCorte."','','','','','',
            '','','','','','','','','','',
            '','','','','','','','','',
            '','','','','','".$f['Importe']."','','','".$nuevoSaldoCapitalCorriente."',
            'PIC','13','','','$nitavu','',NOW(),'','','','','',
            '','','','','','','','',0,'','$IdDelegacion')";
            }else{
                $sql5 = "CALL registrarHistoricoPagos('$NumContrato','$NumMov','".$f['Importe']."','".$fechaOperacion."','','','','','','',
            '','','','','','','','','','',
            '','','','','','','','','',
            '','','','','','".$f['Importe']."','','','".$nuevoSaldoCapitalCorriente."',
            'PIC','13','','','$nitavu','',NOW(),'','','','','',
            '','','','','','','','',0,'','$IdDelegacion')";
            }
            
            echo $sql5;

            if ($Vivienda->query($sql5) == TRUE){
                historia($nitavu,'Ingrese un pago de ahorro al contrato'.$NumContrato);
                $res = TRUE;
            }else{
                historia($nitavu,'ERROR: Al momento de registrar un pago de ahorro'.$sql4);
                $res = FALSE;
            }
            $vuelta ++;

        }  
    }else{
        $res = TRUE;
    }

    return $res;
}

