function financiamientoNoProcedente($NumContrato){
    require("config.php");
    $sql = '';
    if(totalRegistrosdeInformacionCuenta($NumContrato) > 0){
        $financiamiento = Financiamiento($NumContrato);
        $sql = 'SELECT     SUM(HistoricoPagos.FinancPeriodo) - '.$financiamiento.' AS Financiamiento
        FROM   HistoricoPagos 
        WHERE not(HistoricoPagos.tipomov in (3,13,19,63,78,79))
        and HistoricoPagos.cancelado=0 and HistoricoPagos.NumContrato = '.$NumContrato.'';
       
    }else{
        $sql = 'SELECT SUM(HistoricoPagos.FinancPeriodoCubierto+RezFinancCubierto) AS Financiamiento
        FROM HistoricoPagos WHERE NumContrato = '.$NumContrato.' and HistoricoPagos.TipoMov in (3,13,19,78,79,63) and HistoricoPagos.origen<>"RST"
              and HistoricoPagos.cancelado=0';
    }
    //echo $sql;
    $r = $Vivienda -> query($sql); 
  
    while($f = $r -> fetch_array()){
       return $f['Financiamiento'];
    }
}

